const SEGMENTS = new Set([
  'noxh_income', 'valuation', 'sme_credit', 'general_inbound', 'unclassified',
]);

function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return (fenced ? fenced[1] : s).trim();
}

function parseLlmJson(raw) {
  const parsed = JSON.parse(extractJsonString(raw));
  if (parsed == null || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw new Error('JSON_NOT_OBJECT');
  }
  return parsed;
}

function validateClassify(obj) {
  if (!SEGMENTS.has(obj.segment)) throw new Error('INVALID_SEGMENT');
  const score = Number(obj.score);
  if (!Number.isFinite(score) || score < 0 || score > 100) throw new Error('INVALID_SCORE');
  if (typeof obj.interest_key !== 'string' || !obj.interest_key) {
    throw new Error('INVALID_INTEREST_KEY');
  }
  return { segment: obj.segment, score, interest_key: obj.interest_key };
}

const skeleton = $('Auth & Enrich Skeleton').first().json;
const nk = String(skeleton?.normalized_key || '').trim();

const res = $input.first().json;
const raw =
  res.choices?.[0]?.message?.content ??
  res.message?.content ??
  res.text ??
  res.output ??
  res;

try {
  const parsed = parseLlmJson(raw);
  const classify = validateClassify(parsed);
  return [{ json: { ok: true, classify, classify_method: 'llm', parse_error: null } }];
} catch (e) {
  return [{
    json: {
      ok: false,
      classify: null,
      classify_method: 'llm',
      parse_error: e.message,
      raw_preview: String(raw).slice(0, 200),
      normalized_key: nk || null,
    },
  }];
}

const skeleton = $('Auth & Enrich Skeleton').first().json;
const parse = $input.first().json;

const nk = String(skeleton.normalized_key || '').trim();

return [{
  json: {
    ok: false,
    error: parse.parse_error || 'PARSE_JSON',
    message: parse.parse_error || 'LLM output parse failed',
    retryable: false,
    normalized_key: nk || null,
    uid_source: skeleton.uid_source ? String(skeleton.uid_source) : null,
    captured_at: skeleton.captured_at,
    status: 'failed',
    classify_method: 'llm',
    parse_error: parse.parse_error,
    raw_preview: parse.raw_preview,
  },
}];

const skeleton = $('Auth & Enrich Skeleton').first().json;
const item = $input.first().json;

if (!item.ok || !item.classify) {
  throw new Error('Merge skipped: classify not ok');
}

const { segment, score, interest_key } = item.classify;
const method = item.classify_method || 'regex';

const FORBIDDEN = [
  /cam kết.*duyệt/i,
  /lãi suất\s*\d+([.,]\d+)?\s*%/i,
];

const text = skeleton.text || '';
const l0_hits = FORBIDDEN.filter((re) => re.test(text)).map((re) => re.source);

let status = 'classified';
if (score < 60) status = 'review';
if (l0_hits.length > 0) status = 'review';

const record = {
  uid: skeleton.uid,
  uid_source: skeleton.uid_source,
  normalized_key: skeleton.normalized_key,
  captured_at: skeleton.captured_at,
  text,
  segment,
  score,
  interest_key,
  tags: [segment],
  meta: skeleton.meta ?? {},
  classify_method: method,
  consent_basis: skeleton.consent_basis ?? null,
  status,
  l0_forbidden_hits: l0_hits,
};

return [{ json: { ok: true, data: record } }];

const item = $input.first().json;
const record = item.data && typeof item.data === 'object' ? item.data : item;

if (!record.normalized_key) {
  return [{ json: { drive_skip: true, reason: 'no normalized_key' } }];
}

const folderId = $env.GOOGLE_DRIVE_ARCHIVE_FOLDER_ID || '';
if (!folderId || $env.MAGNIX_DRIVE_BACKUP === 'false') {
  return [{ json: { drive_skip: true, reason: 'backup disabled or no folder id' } }];
}

const safeName = String(record.normalized_key).replace(/[^a-zA-Z0-9._-]/g, '_');
const fileName = `${safeName}.jsonl`;
const content = `${JSON.stringify(record)}\n`;
const binaryData = Buffer.from(content, 'utf8').toString('base64');

return [{
  json: {
    fileName,
    normalized_key: record.normalized_key,
    drive_folder_id: folderId,
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'application/x-ndjson',
      fileName,
    },
  },
}];

const SHEET_ID = $env.GOOGLE_SHEET_DATABASE_ID || '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = $env.GOOGLE_SHEET_UID_TAB || 'uid_leads';

const HEADERS = [
  'uid',
  'uid_source',
  'normalized_key',
  'captured_at',
  'text',
  'segment',
  'score',
  'interest_key',
  'tags',
  'meta',
  'classify_method',
  'consent_basis',
  'status',
];

function toRow(record) {
  return [
    String(record.uid ?? ''),
    String(record.uid_source ?? ''),
    String(record.normalized_key ?? ''),
    String(record.captured_at ?? ''),
    String(record.text ?? '').slice(0, 50000),
    String(record.segment ?? 'unclassified'),
    Number(record.score ?? 0),
    String(record.interest_key ?? ''),
    Array.isArray(record.tags) ? record.tags.join(',') : String(record.tags ?? ''),
    (typeof record.meta === 'string' ? record.meta : JSON.stringify(record.meta ?? {})).slice(0, 50000),
    String(record.classify_method ?? ''),
    String(record.consent_basis ?? ''),
    String(record.status ?? 'raw'),
  ];
}

async function sheetRequest(opts) {
  return this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
    json: true,
    ...opts,
  });
}

const base = `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}`;
const readRange = `${TAB}!A:M`;

let existingByKey = new Map();
let nextAppendRow = 2;

try {
  const getRes = await sheetRequest.call(this, {
    method: 'GET',
    url: `${base}/values/${encodeURIComponent(readRange)}`,
  });
  const rows = getRes.values || [];

  if (!rows.length) {
    await sheetRequest.call(this, {
      method: 'PUT',
      url: `${base}/values/${encodeURIComponent(`${TAB}!A1:M1`)}?valueInputOption=USER_ENTERED`,
      body: { values: [HEADERS] },
    });
  } else {
    const headerRow = rows[0].map((h) => String(h ?? '').trim().toLowerCase());
    const nkIdx = headerRow.indexOf('normalized_key');
    const keyCol = nkIdx >= 0 ? nkIdx : 2;
    for (let i = 1; i < rows.length; i += 1) {
      const nk = String(rows[i][keyCol] ?? '').trim();
      if (nk) existingByKey.set(nk, i + 1);
    }
    nextAppendRow = rows.length + 1;
  }
} catch (e) {
  throw new Error(`Sheet read failed (${TAB}): ${e.message}. Tạo tab uid_leads theo ARCHITECTURE_MAGNIX.md §3.1`);
}

const results = [];

for (const item of $input.all()) {
  if (!item.json.ok || !item.json.record) {
    results.push({ json: { ok: false, error: 'SKIP_SHEET', message: item.json.error || item.json.message } });
    continue;
  }

  const record = item.json.record;
  const nk = String(record.normalized_key || '').trim();
  if (!nk) {
    results.push({ json: { ok: false, error: 'MISSING_NORMALIZED_KEY', record } });
    continue;
  }

  const rowValues = toRow(record);
  const existingRow = existingByKey.get(nk);

  try {
    if (existingRow) {
      await sheetRequest.call(this, {
        method: 'PUT',
        url: `${base}/values/${encodeURIComponent(`${TAB}!A${existingRow}:M${existingRow}`)}?valueInputOption=USER_ENTERED`,
        body: { values: [rowValues] },
      });
      results.push({ json: { ok: true, storage: 'sheet_uid_leads', sheet_row: existingRow, action: 'update', normalized_key: nk, record } });
    } else {
      await sheetRequest.call(this, {
        method: 'POST',
        url: `${base}/values/${encodeURIComponent(`${TAB}!A:M`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`,
        body: { values: [rowValues] },
      });
      existingByKey.set(nk, nextAppendRow);
      results.push({ json: { ok: true, storage: 'sheet_uid_leads', sheet_row: nextAppendRow, action: 'create', normalized_key: nk, record } });
      nextAppendRow += 1;
    }
  } catch (e) {
    results.push({ json: { ok: false, error: 'SHEET_UPSERT_FAILED', message: e.message, normalized_key: nk, record } });
  }
}

return results;

const sheet = $input.first().json;
return [{
  json: {
    ok: sheet.ok === true,
    storage: 'google_sheet_primary',
    sheet_action: sheet.action,
    sheet_row: sheet.sheet_row,
    record: sheet.record,
    error: sheet.ok ? undefined : sheet.error,
    message: sheet.ok ? undefined : sheet.message,
  },
}];
